diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..33cebeedee7a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2228,8 +2228,24 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
                                      /*MatchBitReversals*/ true))
         return BitOp;
     }
+    Value *Op2 = II->getArgOperand(2);
+    if (IID == Intrinsic::fshl &&
+        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      KnownBits Known = computeKnownBits(Op2, 0, II);
+      if (Known.getMaxValue().ult(BitWidth)) {
+        Instruction *Shl = BinaryOperator::CreateShl(Op0, Op2);
+        return Shl;
+      }
+    }

-    // Left or right might be masked.
+    if (IID == Intrinsic::fshr &&
+        (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))) {
+      KnownBits Known = computeKnownBits(Op2, 0, II);
+      if (Known.getMaxValue().ult(BitWidth)) {
+        Instruction *LShr = BinaryOperator::CreateLShr(Op1, Op2);
+        return LShr;
+      }
+    }
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

