{"command":"cd /data/zrwang/auto-opt/utils/llvm-122235 && cat << 'EOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp 2231 2250
    Value *Op2 = II->getArgOperand(2);
    if (IID == Intrinsic::fshl &&
        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
      KnownBits Known = computeKnownBits(Op2, 0, II);
      if (Known.getMaxValue().ult(BitWidth)) {
        Instruction *Shl = BinaryOperator::CreateShl(Op0, Op2);
        return Shl;
      }
    }

    if (IID == Intrinsic::fshr &&
        (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))) {
      KnownBits Known = computeKnownBits(Op2, 0, II);
      if (Known.getMaxValue().ult(BitWidth)) {
        // If Op2 is 0, then 32 - 0 = 32, which results in poison for lshr.
        // Wait, fshr(0, x, 0) is x >> 0 (if rotate, it's x).
        // For fshr(0, x, y):
        // (0 << y) | (x >> y)
        // If y is 0, this is x >> 0 = x.
        // Let's not transform fshr if Op2 can be 0. Or maybe we can't just sub.
      }
    }
